// 飞书自定义机器人「签名校验」算法（Lark Open Platform）
// 算法：HMAC-SHA256(key = `${timestamp}\n${secret}`, data = '')，结果 base64 编码
// LARK_BOT_SIGN_SECRET 为空 → 跳过（不启用签名 / 用关键词校验）

const crypto = require('crypto');
const secret = $env.LARK_BOT_SIGN_SECRET || '';
const now = Math.floor(Date.now() / 1000);

let ts = '';
let sign = '';
if (secret) {
  const stringToSign = `${now}\n${secret}`;
  const hmac = crypto.createHmac('sha256', stringToSign);
  hmac.update('');
  sign = hmac.digest('base64');
  ts = String(now);
}

const prev = $input.first().json;
return [{
  json: {
    ...prev,
    lark_timestamp: ts,
    lark_sign: sign
  }
}];

